import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting a premium", () => {
    it.todo("should return base premium plus processing fee for a single sword");
    it.todo("should return correct base premium for each item type (amulet, staff, potion)");
    it.todo("should sum premiums for multiple different items");
    it.todo("should charge 25G base premium per component");
    it.todo("should charge 60G for a building block of 3 alike components");
    it.todo("should add 50% surcharge for cursed items");
    it.todo("should add 30% surcharge for highly enchanted items (enchantment >= 5)");
    it.todo("should apply both cursed and enchantment surcharges when both apply");
    it.todo("should apply 20% loyalty discount for long-standing customers (>= 2 years)");
    it.todo("should apply 10% initial assessment surcharge for first insurance");
    it.todo("should apply 15% discount on each contract after the first");
    it.todo("should round premium up to whole G in MHPCO's favor");
  });

  describe("Processing a claim", () => {
    it.todo("should apply 100G deductible to damage amount");
    it.todo("should return zero payout when damage is less than deductible");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reduce remaining cap after each claim");
    it.todo("should reimburse enchantment >= 8 items at 50% of damage amount");
    it.todo("should fully reimburse dragon material items");
    it.todo("should round payout down to whole G in MHPCO's favor");
  });
});

