const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export function processScenario(input: any): any {
  const results = input.steps.map((step: any) => {
    if (step.op === "quote") {
      const basePremium = BASE_PREMIUMS[step.items[0].type];
      const premium = basePremium + basePremium * 10 / 100;
      return { premium: premium + PROCESSING_FEE };
    }
  });
  return { results };
}

