const PROCESSING_FEE = 5;
const COMPONENT_PREMIUM = 25;
const BUILDING_BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export function processScenario(input: any): any {
  const results = input.steps.map((step: any) => {
    if (step.op === "quote") {
      let basePremium = 0;
      const componentCounts: Record<string, number> = {};
      for (const item of step.items) {
        if (BASE_PREMIUMS[item.type] != null) {
          let itemPremium = BASE_PREMIUMS[item.type];
          if (item.cursed) itemPremium += itemPremium / 2;
          basePremium += itemPremium;
        } else {
          componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
        }
      }
      for (const count of Object.values(componentCounts)) {
        const blocks = Math.floor(count / 3);
        const remainder = count % 3;
        basePremium += blocks * BUILDING_BLOCK_PREMIUM + remainder * COMPONENT_PREMIUM;
      }
      return { premium: basePremium + basePremium / 10 + PROCESSING_FEE };
    }
  });
  return { results };
}

