          },
          {
            op: "claim",
            policy: 0,
            incident: {
              cause: "spell mishap",
              damages: [{ itemType: "sword", amount: 400 }],
            },
          },
        ],
      });
      expect(result.results[1].payout).toBe(100);
      expect(result.results[1].remainingCap).toBe(1900);
    });
    it.todo("should fully reimburse dragon material items");
    it.todo("should round payout down to whole G in MHPCO's favor");
  });
});

